  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "specPath": ".arkpilot/autopilot/spec.md",
  "version": "arkpilot-a2ui/v2",
  "appName": "手作·印记",
  "executionMode": "headless-logic-first",
  "notes": "Authored during headless logic phase. Visual layout, theme tokens, icon system, and final page components are deferred to the visual integration phase once page-*.html / design-alignment.md arrive. Logic modules (models + AppStore) are the source of truth for all bindings below.",
  "dataModel": {
    "entities": {
      "CraftSpecialty": {
        "values": ["pottery", "weaving", "woodworking", "floral", "leather", "other"],
        "labels": { "pottery": "陶艺", "weaving": "织染", "woodworking": "木作", "floral": "花艺", "leather": "皮具", "other": "其他" }
      },
      "SkillLevel": { "values": ["beginner", "intermediate", "advanced"] },
      "Member": {
        "fields": {
          "id": "string",
          "name": "string",
          "phone": "string",
          "birthday": "string (YYYY-MM-DD|empty)",
          "crafts": "CraftSpecialty[]",
          "skillLevel": "SkillLevel",
          "notes": "string",
          "portfolio": "PortfolioImage[]",
          "pointsBalance": "number",
          "lastVisitDate": "string (YYYY-MM-DD|empty)",
          "createdAt": "number (ms)",
          "archived": "boolean"
        }
      },
      "PortfolioImage": { "fields": { "id": "string", "uri": "string", "caption": "string" } },
      "PointsEntry": {
        "fields": {
          "id": "string",
          "memberId": "string",
          "delta": "number (signed)",
          "reason": "PointsReason",
          "refId": "string (courseId|inventoryId|empty)",
          "createdAt": "number (ms)",
          "memo": "string"
        }
      },
      "PointsReason": { "values": ["checkin", "spend", "redeem", "adjust", "course"] },
      "CheckInRecord": { "fields": { "id": "string", "memberId": "string", "date": "string (YYYY-MM-DD)", "createdAt": "number (ms)" } },
      "Course": {
        "fields": {
          "id": "string",
          "title": "string",
          "craft": "CraftSpecialty",
          "date": "string (YYYY-MM-DD)",
          "startTime": "string (HH:mm)",
          "durationMin": "number",
          "instructor": "string",
          "capacity": "number",
          "bookedCount": "number",
          "priceCny": "number",
          "inventoryLinks": "InventoryLink[]",
          "studentIds": "string[]",
          "createdAt": "number (ms)"
        }
      },
      "InventoryLink": { "fields": { "itemId": "string", "quantityPerSeat": "number" } },
      "CourseBooking": { "fields": { "id": "string", "courseId": "string", "memberId": "string", "createdAt": "number (ms)" } },
      "InventoryItem": {
        "fields": {
          "id": "string",
          "name": "string",
          "unit": "string",
          "stock": "number",
          "lowStockThreshold": "number",
          "createdAt": "number (ms)"
        }
      },
      "InventoryDeduction": { "fields": { "id": "string", "itemId": "string", "quantity": "number", "reason": "string", "refId": "string", "createdAt": "number (ms)" } },
      "ReminderLog": { "fields": { "id": "string", "memberId": "string", "sentAt": "number (ms)", "channel": "in-app", "note": "string" } },
      "Settings": {
        "fields": {
          "checkinPoints": "number (default 10)",
          "spendRatio": "number (CNY->points, default 1 point per 1 CNY)",
          "dormantThresholdDays": "number (default 60)",
          "notificationsEnabled": "boolean (default true)"
        }
      }
    },
    "computedState": {
      "dormantMembers": "members whose lastVisitDate is older than settings.dormantThresholdDays, excluding archived",
      "lowStockItems": "inventory where stock <= lowStockThreshold",
      "todayCourses": "courses with date == today",
      "stats.totalPointsToday": "sum of positive PointsEntry.delta created today",
      "stats.checkinsToday": "count of CheckInRecord with date == today",
      "stats.coursesToday": "count of todayCourses",
      "reminders.count": "count of dormantMembers",
      "course.seatsRemaining": "capacity - bookedCount"
    },
    "persistence": {
      "strategy": "preferences-backed JSON for Settings + first-run empty state; runtime collections held in AppStore singleton. Persistence adapter is pluggable; default in-memory for the headless build, preferences wiring added when runtime context is available.",
      "noSeedData": true
    }
  },
  "services": {
    "AppStore": {
      "role": "singleton observable store (@ObservedV2/@Trace). Owns all collections + settings and all mutating business methods. Pages obtain it via AppStore.instance().",
      "methods": [
        "addMember/updateMember/archiveMember",
        "checkIn(memberId) -> awards settings.checkinPoints, updates lastVisitDate, records CheckInRecord + PointsEntry",
        "recordSpend(memberId, amountCny, memo?) -> awards floor(amountCny * spendRatio) points",
        "redeemPoints(memberId, points, memo) -> deducts points if balance allows",
        "adjustPoints(memberId, delta, memo) -> manual adjustment",
        "addCourse/updateCourse",
        "bookCourse(courseId, memberId) -> increments bookedCount, adds studentId, deducts linked inventory per seat, writes InventoryDeduction; fails when full",
        "cancelCourse(courseId, memberId) -> reverses seat + restocks linked inventory",
        "addInventory/updateInventory/restock(itemId, quantity)",
        "dormantMembers() -> computed list",
        "sendReminder(memberId, note?) -> writes ReminderLog",
        "saveSettings(partial) -> updates settings",
        "todayCourses(), todayStats(), lowStockItems()"
      ]
    },
    "IdGen": { "role": "deterministic-ish id generator (counter + timestamp) since Math.random is unavailable in some contexts" },
    "DateUtil": { "role": "today() YYYY-MM-DD, daysBetween, addDays, monthLabel helpers using a fixed now injected by caller to avoid Date.now in pure logic where restricted" }
  },
  "stateMachine": {
    "courseBooking": {
      "states": ["available", "booked", "full"],
      "transitions": [
        { "from": "available", "event": "book-course", "to": "booked", "guard": "member not already enrolled & seatsRemaining>0", "sideEffects": ["+seat", "+studentId", "deduct linked inventory", "+PointsEntry(course)? no", "+InventoryDeduction"] },
        { "from": "booked", "event": "book-course", "to": "full|booked", "guard": "if seatsRemaining==0 -> full" },
        { "from": "booked|full", "event": "cancel-course", "to": "available|booked", "sideEffects": ["-seat", "-studentId", "restock linked inventory"] }
      ]
    },
    "memberLifecycle": {
      "states": ["active", "dormant", "archived"],
      "transitions": [
        { "event": "checkin-member", "to": "active", "sideEffects": ["lastVisitDate=today", "+points"] },
        { "event": "archive", "to": "archived" },
        { "auto": "lastVisit older than threshold", "to": "dormant" }
      ]
    },
    "points": {
      "transitions": [
        { "event": "checkin", "delta": "+checkinPoints" },
        { "event": "spend", "delta": "+floor(amount*ratio)" },
        { "event": "redeem", "delta": "-points", "guard": "balance >= points" },
        { "event": "adjust", "delta": "signed" }
      ]
    }
  },
  "interactionFlows": [
    {
      "name": "check-in",
      "trigger": "home-checkin-button | member-checkin-button",
