// Models.ets
//
// Headless data model layer for 手作·印记.
// All entities are @ObservedV2 so the AppStore can mutate fields in place and
// any @Component that holds a reference re-renders through @Trace.
//
// ArkTS strict notes (this repo, SDK 6.0.2(22)):
// - No spreads / no indexed object access / no utility types: keep construction explicit.
// - Enum-like unions are real unions + helper functions (not index lookup).

export type CraftSpecialty = 'pottery' | 'weaving' | 'woodworking' | 'floral' | 'leather' | 'other';
export type SkillLevel = 'beginner' | 'intermediate' | 'advanced';
export type PointsReason = 'checkin' | 'spend' | 'redeem' | 'adjust' | 'course';

export function craftLabel(c: CraftSpecialty): string {
  if (c === 'pottery') {
    return '陶艺';
  } else if (c === 'weaving') {
    return '织染';
  } else if (c === 'woodworking') {
    return '木作';
  } else if (c === 'floral') {
    return '花艺';
  } else if (c === 'leather') {
    return '皮具';
  }
  return '其他';
}

export function skillLabel(s: SkillLevel): string {
  if (s === 'beginner') {
    return '入门';
  } else if (s === 'intermediate') {
    return '进阶';
  }
  return '资深';
}

export function pointsReasonLabel(r: PointsReason): string {
  if (r === 'checkin') {
    return '签到';
  } else if (r === 'spend') {
    return '消费';
  } else if (r === 'redeem') {
    return '兑换';
  } else if (r === 'adjust') {
    return '调整';
  }
  return '课程';
}

@ObservedV2
export class PortfolioImage {
  @Trace id: string;
  @Trace uri: string;
  @Trace caption: string;

  constructor(id: string, uri: string, caption: string) {
    this.id = id;
    this.uri = uri;
    this.caption = caption;
  }
}

@ObservedV2
export class Member {
  @Trace id: string;
  @Trace name: string;
  @Trace phone: string;
  @Trace birthday: string;
  @Trace crafts: CraftSpecialty[];
  @Trace skillLevel: SkillLevel;
  @Trace notes: string;
  @Trace portfolio: PortfolioImage[];
  @Trace pointsBalance: number;
  @Trace lastVisitDate: string;
  @Trace createdAt: number;
  @Trace archived: boolean;

  constructor(id: string, name: string, phone: string) {
    this.id = id;
    this.name = name;
    this.phone = phone;
    this.birthday = '';
    this.crafts = [];
    this.skillLevel = 'beginner';
    this.notes = '';
    this.portfolio = [];
    this.pointsBalance = 0;
    this.lastVisitDate = '';
    this.createdAt = 0;
    this.archived = false;
  }
}

@ObservedV2
export class PointsEntry {
  @Trace id: string;
  @Trace memberId: string;
  @Trace delta: number;
  @Trace reason: PointsReason;
  @Trace refId: string;
  @Trace createdAt: number;
  @Trace memo: string;

  constructor(id: string, memberId: string, delta: number, reason: PointsReason,
              refId: string, createdAt: number, memo: string) {
    this.id = id;
    this.memberId = memberId;
    this.delta = delta;
    this.reason = reason;
    this.refId = refId;
    this.createdAt = createdAt;
    this.memo = memo;
  }
}

@ObservedV2
export class CheckInRecord {
  @Trace id: string;
  @Trace memberId: string;
  @Trace date: string;
  @Trace createdAt: number;

  constructor(id: string, memberId: string, date: string, createdAt: number) {
    this.id = id;
    this.memberId = memberId;
    this.date = date;
    this.createdAt = createdAt;
  }
}

export class InventoryLink {
  itemId: string;
  quantityPerSeat: number;

  constructor(itemId: string, quantityPerSeat: number) {
    this.itemId = itemId;
    this.quantityPerSeat = quantityPerSeat;
  }
}

@ObservedV2
export class Course {
  @Trace id: string;
  @Trace title: string;
  @Trace craft: CraftSpecialty;
  @Trace date: string;
  @Trace startTime: string;
  @Trace durationMin: number;
  @Trace instructor: string;
  @Trace capacity: number;
  @Trace bookedCount: number;
  @Trace priceCny: number;
  @Trace inventoryLinks: InventoryLink[];
  @Trace studentIds: string[];
  @Trace createdAt: number;

  constructor(id: string, title: string, craft: CraftSpecialty, date: string) {
    this.id = id;
    this.title = title;
    this.craft = craft;
    this.date = date;
    this.startTime = '';
    this.durationMin = 0;
    this.instructor = '';
    this.capacity = 0;
    this.bookedCount = 0;
    this.priceCny = 0;
    this.inventoryLinks = [];
    this.studentIds = [];
    this.createdAt = 0;
  }

  seatsRemaining(): number {
    const remaining: number = this.capacity - this.bookedCount;
    return remaining > 0 ? remaining : 0;
  }

  isFull(): boolean {
    return this.bookedCount >= this.capacity;
  }
}

@ObservedV2
export class CourseBooking {
  @Trace id: string;
  @Trace courseId: string;
  @Trace memberId: string;
  @Trace createdAt: number;

  constructor(id: string, courseId: string, memberId: string, createdAt: number) {
    this.id = id;
    this.courseId = courseId;
    this.memberId = memberId;
    this.createdAt = createdAt;
  }
}

@ObservedV2
export class InventoryItem {
  @Trace id: string;
  @Trace name: string;
  @Trace unit: string;
  @Trace stock: number;
  @Trace lowStockThreshold: number;
  @Trace createdAt: number;

  constructor(id: string, name: string, unit: string) {
    this.id = id;
    this.name = name;
    this.unit = unit;
    this.stock = 0;
    this.lowStockThreshold = 0;
    this.createdAt = 0;
  }

  isLowStock(): boolean {
    return this.stock <= this.lowStockThreshold;
  }
}

@ObservedV2
export class InventoryDeduction {
  @Trace id: string;
  @Trace itemId: string;
  @Trace quantity: number;
  @Trace reason: string;
  @Trace refId: string;
  @Trace createdAt: number;

  constructor(id: string, itemId: string, quantity: number, reason: string,
              refId: string, createdAt: number) {
    this.id = id;
    this.itemId = itemId;
    this.quantity = quantity;
    this.reason = reason;
    this.refId = refId;
    this.createdAt = createdAt;
  }
}

@ObservedV2
export class ReminderLog {
  @Trace id: string;
  @Trace memberId: string;
  @Trace sentAt: number;
  @Trace note: string;

  constructor(id: string, memberId: string, sentAt: number, note: string) {
    this.id = id;
    this.memberId = memberId;
    this.sentAt = sentAt;
    this.note = note;
  }
}

@ObservedV2
export class Settings {
  @Trace checkinPoints: number;
  @Trace spendRatio: number;
  @Trace dormantThresholdDays: number;
  @Trace notificationsEnabled: boolean;

  constructor() {
    this.checkinPoints = 10;
    this.spendRatio = 1;
    this.dormantThresholdDays = 60;
    this.notificationsEnabled = true;
  }
}

// Immutable snapshot returned to the UI for stats/derived values.
export class StatsSnapshot {
  totalPointsToday: number = 0;
  checkinsToday: number = 0;
  coursesToday: number = 0;
  dormantCount: number = 0;
  lowStockCount: number = 0;
}

// Result of a mutating operation. UI layer turns failures into feedback.
export class OperationResult {
  ok: boolean;
  message: string;

  constructor(ok: boolean, message: string) {
    this.ok = ok;
    this.message = message;
  }

  static success(message: string): OperationResult {
    return new OperationResult(true, message);
  }

  static failure(message: string): OperationResult {
    return new OperationResult(false, message);
  }
}

