    this.createdAt = 0;
  }

  seatsRemaining(): number {
    const remaining: number = this.capacity - this.bookedCount;
    return remaining > 0 ? remaining : 0;
  }

  isFull(): boolean {
    return this.bookedCount >= this.capacity;
  }
}

@ObservedV2
export class CourseBooking {
  @Trace id: string;
  @Trace courseId: string;
  @Trace memberId: string;
  @Trace createdAt: number;

  constructor(id: string, courseId: string, memberId: string, createdAt: number) {
    this.id = id;
    this.courseId = courseId;
    this.memberId = memberId;
    this.createdAt = createdAt;
  }
}

@ObservedV2
export class InventoryItem {
  @Trace id: string;
  @Trace name: string;
  @Trace unit: string;
  @Trace stock: number;
  @Trace lowStockThreshold: number;
  @Trace createdAt: number;

  constructor(id: string, name: string, unit: string) {
    this.id = id;
    this.name = name;
    this.unit = unit;
    this.stock = 0;
    this.lowStockThreshold = 0;
    this.createdAt = 0;
  }

  isLowStock(): boolean {
    return this.stock <= this.lowStockThreshold;
  }
}

@ObservedV2
export class InventoryDeduction {
  @Trace id: string;
  @Trace itemId: string;
  @Trace quantity: number;
  @Trace reason: string;
  @Trace refId: string;
  @Trace createdAt: number;

  constructor(id: string, itemId: string, quantity: number, reason: string,
              refId: string, createdAt: number) {
    this.id = id;
    this.itemId = itemId;
    this.quantity = quantity;
    this.reason = reason;
    this.refId = refId;
    this.createdAt = createdAt;
  }
}

@ObservedV2
export class ReminderLog {
  @Trace id: string;
  @Trace memberId: string;
  @Trace sentAt: number;
  @Trace note: string;

  constructor(id: string, memberId: string, sentAt: number, note: string) {
    this.id = id;
    this.memberId = memberId;
    this.sentAt = sentAt;
    this.note = note;
  }
}

@ObservedV2
export class Settings {
  @Trace checkinPoints: number;
  @Trace spendRatio: number;
  @Trace dormantThresholdDays: number;
  @Trace notificationsEnabled: boolean;

  constructor() {
    this.checkinPoints = 10;
    this.spendRatio = 1;
    this.dormantThresholdDays = 60;
    this.notificationsEnabled = true;
  }
}

// Immutable snapshot returned to the UI for stats/derived values.
export class StatsSnapshot {
  totalPointsToday: number = 0;
  checkinsToday: number = 0;
  coursesToday: number = 0;
  dormantCount: number = 0;
  lowStockCount: number = 0;
}

// Result of a mutating operation. UI layer turns failures into feedback.
export class OperationResult {
  ok: boolean;
  message: string;

  constructor(ok: boolean, message: string) {
    this.ok = ok;
    this.message = message;
  }

  static success(message: string): OperationResult {
    return new OperationResult(true, message);
  }

  static failure(message: string): OperationResult {
    return new OperationResult(false, message);
  }
}

