// DateUtil.ets
//
// Date helpers used by AppStore. Pure functions; callers pass an explicit `now`
// (ms) so the logic stays deterministic and avoids relying on Date.now where the
// surrounding environment may restrict it. UI code passes the real wall clock.

export class DateUtil {
  // Formats a millisecond timestamp as YYYY-MM-DD in local time.
  static toYmd(ms: number): string {
    const d: Date = new Date(ms);
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    return `${y}-${m < 10 ? '0' + m : m}-${day < 10 ? '0' + day : day}`;
  }

  // Parses a YYYY-MM-DD string to a local-time midnight timestamp.
  // Returns 0 for empty/invalid input.
  static parseYmd(ymd: string): number {
    if (ymd === '') {
      return 0;
    }
    const parts: string[] = ymd.split('-');
    if (parts.length !== 3) {
      return 0;
    }
    const y: number = parseInt(parts[0], 10);
    const m: number = parseInt(parts[1], 10);
    const d: number = parseInt(parts[2], 10);
    if (Number.isNaN(y) || Number.isNaN(m) || Number.isNaN(d)) {
      return 0;
    }
    return new Date(y, m - 1, d).getTime();
  }

  // Whole-day difference: b - a in days.
  static daysBetween(a: number, b: number): number {
    if (a === 0) {
      return Number.MAX_SAFE_INTEGER;
    }
    const dayMs: number = 24 * 60 * 60 * 1000;
    const diff: number = b - a;
    return Math.floor(diff / dayMs);
  }

  // Human month label for calendar: "2026年6月".
  static monthLabel(ms: number): string {
    const d: Date = new Date(ms);
    return `${d.getFullYear()}年${d.getMonth() + 1}月`;
  }

  static startOfMonth(ms: number): number {
    const d: Date = new Date(ms);
    return new Date(d.getFullYear(), d.getMonth(), 1).getTime();
  }

  // Adds days to a timestamp.
  static addDays(ms: number, days: number): number {
    return ms + days * 24 * 60 * 60 * 1000;
  }
}

