// AppStore.ets
//
// Headless feature logic: central observable store + business methods for 手作·印记.
//
// Reactivity: AppStore is @ObservedV2; collection arrays and Settings are @Trace.
// @Component pages obtain it via AppStore.instance() and hold the reference in a
// @Local/@State field so @Trace mutations trigger re-render. Model entities are
// themselves @ObservedV2/@Trace, so in-place field edits also propagate.
//
// Strict ArkTS notes applied here:
// - No spreads: arrays built with push/indexed assignment.
// - No indexed object access / no utility types.
// - This is a singleton via a static field; static accessors do not use `this`.
//
// Data strategy (per ui-behavior.json): in-memory runtime state, first-run empty
// (no seeded demo data). A preferences-backed persistence adapter can be wired in
// later without changing this service's public API.

import {
  Member,
  PortfolioImage,
  PointsEntry,
  CheckInRecord,
  Course,
  CourseBooking,
  InventoryItem,
  InventoryDeduction,
  ReminderLog,
  Settings,
  StatsSnapshot,
  OperationResult,
  CraftSpecialty,
  SkillLevel,
  PointsReason,
  InventoryLink,
} from '../model/Models';
import { DateUtil } from '../common/DateUtil';

@ObservedV2
export class AppStore {
  @Trace members: Member[] = [];
  @Trace pointsEntries: PointsEntry[] = [];
  @Trace checkIns: CheckInRecord[] = [];
  @Trace courses: Course[] = [];
  @Trace bookings: CourseBooking[] = [];
  @Trace inventory: InventoryItem[] = [];
  @Trace deductions: InventoryDeduction[] = [];
  @Trace reminders: ReminderLog[] = [];
  @Trace settings: Settings = new Settings();

  // Bumped on any structural change so list bindings that depend on derived
  // filters can re-evaluate even when the underlying array identity is unchanged.
  @Trace revision: number = 0;

  private static instanceValue: AppStore | null = null;
  private idCounter: number = 1;

  static instance(): AppStore {
    if (AppStore.instanceValue === null) {
      AppStore.instanceValue = new AppStore();
    }
    return AppStore.instanceValue;
  }

  private nextId(prefix: string): string {
    const n: number = this.idCounter;
    this.idCounter += 1;
    return `${prefix}_${n}`;
  }

  private nowMs(): number {
    return new Date().getTime();
  }

  private bump(): void {
    this.revision += 1;
  }

  // ---------- Member CRUD ----------

  createMember(name: string, phone: string): Member {
    const m: Member = new Member(this.nextId('m'), name, phone);
    m.createdAt = this.nowMs();
    this.members.push(m);
    this.bump();
    return m;
  }

  findMember(id: string): Member | null {
    for (let i = 0; i < this.members.length; i++) {
      if (this.members[i].id === id) {
        return this.members[i];
      }
    }
    return null;
  }

  updateMemberProfile(id: string, name: string, phone: string, birthday: string,
                      crafts: CraftSpecialty[], skill: SkillLevel, notes: string): void {
    const m: Member | null = this.findMember(id);
    if (m === null) {
      return;
    }
    m.name = name;
    m.phone = phone;
    m.birthday = birthday;
    m.crafts = crafts;
    m.skillLevel = skill;
    m.notes = notes;
    this.bump();
  }

  addPortfolioImage(memberId: string, uri: string, caption: string): void {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return;
    }
    m.portfolio.push(new PortfolioImage(this.nextId('p'), uri, caption));
    this.bump();
  }

  removePortfolioImage(memberId: string, imageId: string): void {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return;
    }
    const next: PortfolioImage[] = [];
    for (let i = 0; i < m.portfolio.length; i++) {
      if (m.portfolio[i].id !== imageId) {
        next.push(m.portfolio[i]);
      }
    }
    m.portfolio = next;
    this.bump();
  }

  archiveMember(id: string): void {
    const m: Member | null = this.findMember(id);
    if (m === null) {
      return;
    }
    m.archived = true;
    this.bump();
  }

  // ---------- Points / Check-in ----------

  // Returns failure if the member was already checked in today (same-day default).
  checkIn(memberId: string, now?: number): OperationResult {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    const ts: number = now !== undefined ? now : this.nowMs();
    const today: string = DateUtil.toYmd(ts);
    for (let i = 0; i < this.checkIns.length; i++) {
      if (this.checkIns[i].memberId === memberId && this.checkIns[i].date === today) {
        return OperationResult.failure('今日已签到');
      }
    }
    this.checkIns.push(new CheckInRecord(this.nextId('c'), memberId, today, ts));
    m.lastVisitDate = today;
    this.awardPoints(memberId, this.settings.checkinPoints, 'checkin', '', '每日签到');
    this.bump();
    return OperationResult.success('签到成功');
  }

  recordSpend(memberId: string, amountCny: number, memo: string): OperationResult {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    if (amountCny <= 0) {
      return OperationResult.failure('消费金额需大于 0');
    }
    const earned: number = Math.floor(amountCny * this.settings.spendRatio);
    if (earned > 0) {
      this.awardPoints(memberId, earned, 'spend', '', memo);
    }
    const ts: number = this.nowMs();
    m.lastVisitDate = DateUtil.toYmd(ts);
    this.bump();
    return OperationResult.success(`消费已记录，积分 +${earned}`);
  }

  redeemPoints(memberId: string, points: number, memo: string): OperationResult {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    if (points <= 0) {
      return OperationResult.failure('兑换积分需大于 0');
    }
    if (m.pointsBalance < points) {
      return OperationResult.failure('积分余额不足');
    }
    this.awardPoints(memberId, -points, 'redeem', '', memo);
    this.bump();
    return OperationResult.success('兑换成功');
  }

  adjustPoints(memberId: string, delta: number, memo: string): OperationResult {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    if (delta === 0) {
      return OperationResult.failure('调整值不能为 0');
    }
    if (delta < 0 && m.pointsBalance + delta < 0) {
      return OperationResult.failure('调整后积分不能为负');
    }
    this.awardPoints(memberId, delta, 'adjust', '', memo);
    this.bump();
    return OperationResult.success('积分已调整');
  }

  private awardPoints(memberId: string, delta: number, reason: PointsReason,
                      refId: string, memo: string): void {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return;
    }
    m.pointsBalance += delta;
    if (m.pointsBalance < 0) {
      m.pointsBalance = 0;
    }
    this.pointsEntries.push(
      new PointsEntry(this.nextId('pe'), memberId, delta, reason, refId, this.nowMs(), memo));
  }

  pointsHistoryFor(memberId: string): PointsEntry[] {
    const out: PointsEntry[] = [];
    for (let i = 0; i < this.pointsEntries.length; i++) {
      if (this.pointsEntries[i].memberId === memberId) {
        out.push(this.pointsEntries[i]);
      }
    }
    // Most recent first.
    out.sort((a: PointsEntry, b: PointsEntry) => b.createdAt - a.createdAt);
    return out;
  }

  // ---------- Course CRUD + booking ----------

  createCourse(title: string, craft: CraftSpecialty, date: string): Course {
    const c: Course = new Course(this.nextId('c'), title, craft, date);
    c.createdAt = this.nowMs();
    this.courses.push(c);
    this.bump();
    return c;
  }

  findCourse(id: string): Course | null {
    for (let i = 0; i < this.courses.length; i++) {
      if (this.courses[i].id === id) {
        return this.courses[i];
      }
    }
    return null;
  }

  updateCourseSchedule(id: string, title: string, craft: CraftSpecialty, date: string,
                       startTime: string, durationMin: number, instructor: string,
                       capacity: number, priceCny: number, links: InventoryLink[]): void {
    const c: Course | null = this.findCourse(id);
    if (c === null) {
      return;
    }
    c.title = title;
    c.craft = craft;
    c.date = date;
    c.startTime = startTime;
    c.durationMin = durationMin;
    c.instructor = instructor;
    c.capacity = capacity;
    c.priceCny = priceCny;
    c.inventoryLinks = links;
    this.bump();
  }

  bookCourse(courseId: string, memberId: string): OperationResult {
    const c: Course | null = this.findCourse(courseId);
    if (c === null) {
      return OperationResult.failure('未找到课程');
    }
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    if (c.isFull()) {
      return OperationResult.failure('课程已满员');
    }
    for (let i = 0; i < c.studentIds.length; i++) {
      if (c.studentIds[i] === memberId) {
        return OperationResult.failure('该会员已报名');
      }
    }
    c.bookedCount += 1;
    c.studentIds.push(memberId);
    this.bookings.push(new CourseBooking(this.nextId('b'), courseId, memberId, this.nowMs()));
    // Deduct linked inventory: quantityPerSeat applied once per booking.
    this.deductForCourse(c);
    m.lastVisitDate = DateUtil.toYmd(this.nowMs());
    this.bump();
    return OperationResult.success('预约成功');
  }

  cancelCourse(courseId: string, memberId: string): OperationResult {
    const c: Course | null = this.findCourse(courseId);
    if (c === null) {
      return OperationResult.failure('未找到课程');
    }
    let enrolled: boolean = false;
    const nextStudents: string[] = [];
    for (let i = 0; i < c.studentIds.length; i++) {
      if (c.studentIds[i] === memberId) {
        enrolled = true;
      } else {
        nextStudents.push(c.studentIds[i]);
      }
    }
    if (!enrolled) {
      return OperationResult.failure('该会员未报名此课程');
    }
    c.studentIds = nextStudents;
    c.bookedCount = c.bookedCount > 0 ? c.bookedCount - 1 : 0;
    // Restock linked inventory for the released seat.
    this.restockForCourse(c);
    // Remove matching booking records.
    const nextBookings: CourseBooking[] = [];
    for (let i = 0; i < this.bookings.length; i++) {
      const b: CourseBooking = this.bookings[i];
      if (!(b.courseId === courseId && b.memberId === memberId)) {
        nextBookings.push(b);
      }
    }
    this.bookings = nextBookings;
    this.bump();
    return OperationResult.success('已取消预约');
  }

  private deductForCourse(c: Course): void {
    for (let i = 0; i < c.inventoryLinks.length; i++) {
      const link: InventoryLink = c.inventoryLinks[i];
      const item: InventoryItem | null = this.findInventory(link.itemId);
      if (item === null) {
        continue;
      }
      const qty: number = link.quantityPerSeat;
      item.stock -= qty;
      this.deductions.push(new InventoryDeduction(
        this.nextId('d'), item.id, qty, `课程预约: ${c.title}`, c.id, this.nowMs()));
    }
  }

  private restockForCourse(c: Course): void {
    for (let i = 0; i < c.inventoryLinks.length; i++) {
      const link: InventoryLink = c.inventoryLinks[i];
      const item: InventoryItem | null = this.findInventory(link.itemId);
      if (item === null) {
        continue;
      }
      item.stock += link.quantityPerSeat;
    }
  }

  coursesForDate(date: string): Course[] {
    const out: Course[] = [];
    for (let i = 0; i < this.courses.length; i++) {
      if (this.courses[i].date === date) {
        out.push(this.courses[i]);
      }
    }
    out.sort((a: Course, b: Course) => a.startTime.localeCompare(b.startTime));
    return out;
  }

  // ---------- Inventory ----------

  createInventoryItem(name: string, unit: string, stock: number, lowStockThreshold: number): InventoryItem {
    const it: InventoryItem = new InventoryItem(this.nextId('i'), name, unit);
    it.stock = stock;
    it.lowStockThreshold = lowStockThreshold;
    it.createdAt = this.nowMs();
    this.inventory.push(it);
    this.bump();
    return it;
  }

  findInventory(id: string): InventoryItem | null {
    for (let i = 0; i < this.inventory.length; i++) {
      if (this.inventory[i].id === id) {
        return this.inventory[i];
      }
    }
    return null;
  }

  updateInventoryItem(id: string, name: string, unit: string, lowStockThreshold: number): void {
    const it: InventoryItem | null = this.findInventory(id);
    if (it === null) {
      return;
    }
    it.name = name;
    it.unit = unit;
    it.lowStockThreshold = lowStockThreshold;
    this.bump();
  }

  restock(id: string, quantity: number, reason: string): OperationResult {
    const it: InventoryItem | null = this.findInventory(id);
    if (it === null) {
      return OperationResult.failure('未找到库存项');
    }
    if (quantity <= 0) {
      return OperationResult.failure('入库数量需大于 0');
    }
    it.stock += quantity;
    this.deductions.push(new InventoryDeduction(
      this.nextId('d'), id, -quantity, reason.length > 0 ? reason : '手动入库', '', this.nowMs()));
    this.bump();
    return OperationResult.success('入库成功');
  }

  deductionsFor(itemId: string): InventoryDeduction[] {
    const out: InventoryDeduction[] = [];
    for (let i = 0; i < this.deductions.length; i++) {
      if (this.deductions[i].itemId === itemId) {
        out.push(this.deductions[i]);
      }
    }
    out.sort((a: InventoryDeduction, b: InventoryDeduction) => b.createdAt - a.createdAt);
    return out;
  }

  lowStockItems(): InventoryItem[] {
    const out: InventoryItem[] = [];
    for (let i = 0; i < this.inventory.length; i++) {
      if (this.inventory[i].isLowStock()) {
        out.push(this.inventory[i]);
      }
    }
    return out;
  }

  // ---------- Dormant members + reminders ----------

  dormantMembers(now?: number): Member[] {
    const ts: number = now !== undefined ? now : this.nowMs();
    const nowDay: number = DateUtil.parseYmd(DateUtil.toYmd(ts));
    const threshold: number = this.settings.dormantThresholdDays;
    const out: Member[] = [];
    for (let i = 0; i < this.members.length; i++) {
      const m: Member = this.members[i];
      if (m.archived) {
        continue;
      }
      const last: number = DateUtil.parseYmd(m.lastVisitDate);
      const days: number = DateUtil.daysBetween(last === 0 ? 0 : last, nowDay);
      if (days > threshold) {
        out.push(m);
      }
    }
    return out;
  }

  sendReminder(memberId: string, note: string): OperationResult {
    const m: Member | null = this.findMember(memberId);
    if (m === null) {
      return OperationResult.failure('未找到会员');
    }
    this.reminders.push(new ReminderLog(this.nextId('r'), memberId, this.nowMs(),
      note.length > 0 ? note : '温馨提醒：好久没来工作室啦，新课程等你来体验。'));
    this.bump();
    return OperationResult.success('提醒已记录');
  }

  // ---------- Settings ----------

  saveSettings(checkinPoints: number, spendRatio: number, dormantThresholdDays: number,
              notificationsEnabled: boolean): void {
    this.settings.checkinPoints = checkinPoints;
    this.settings.spendRatio = spendRatio;
    this.settings.dormantThresholdDays = dormantThresholdDays;
    this.settings.notificationsEnabled = notificationsEnabled;
    this.bump();
  }

  // ---------- Derived / stats ----------

  todayStats(now?: number): StatsSnapshot {
    const ts: number = now !== undefined ? now : this.nowMs();
    const today: string = DateUtil.toYmd(ts);
    const snap: StatsSnapshot = new StatsSnapshot();
    snap.checkinsToday = 0;
    for (let i = 0; i < this.checkIns.length; i++) {
      if (this.checkIns[i].date === today) {
        snap.checkinsToday += 1;
      }
    }
    snap.totalPointsToday = 0;
    for (let i = 0; i < this.pointsEntries.length; i++) {
      const e: PointsEntry = this.pointsEntries[i];
      if (e.delta > 0 && DateUtil.toYmd(e.createdAt) === today) {
        snap.totalPointsToday += e.delta;
      }
    }
    snap.coursesToday = this.coursesForDate(today).length;
    snap.dormantCount = this.dormantMembers(ts).length;
    snap.lowStockCount = this.lowStockItems().length;
    return snap;
  }
}
